-- 104 班別對照表（代碼/班別名稱 → 上下班時間）— 持久化供「未來匯入班表」把代碼轉時間用
-- 2026-06-17  來源:104班別.xlsx。班表 shift 多為「{店代號}-{班別名稱}」,以 name 尾碼比對。
BEGIN;

CREATE TABLE IF NOT EXISTS public.shift_code_times (
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  code TEXT, name TEXT NOT NULL UNIQUE,
  start_time TIME NOT NULL, end_time TIME NOT NULL,
  cross_midnight BOOLEAN NOT NULL DEFAULT false
);
ALTER TABLE public.shift_code_times ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS sct_read ON public.shift_code_times;
CREATE POLICY sct_read ON public.shift_code_times FOR SELECT TO authenticated USING (true);
GRANT SELECT ON public.shift_code_times TO authenticated; GRANT ALL ON public.shift_code_times TO service_role;


COMMIT;
NOTIFY pgrst, 'reload schema';
